function scanParallelConflicts(content: any[]): { conflict: boolean; tools: string[] } | null {
  const toolResults = content.filter((c): c is any => c.type === 'tool_result');
  const finalText = content.find((c): c is any => c.type === 'text')?.text || '';

  const weatherResult = toolResults.find(t => t.tool_use_id?.includes('weather'))?.content;
  const calendarResult = toolResults.find(t => t.tool_use_id?.includes('calendar'))?.content;

  if (weatherResult && calendarResult && finalText.includes('weather') && finalText.includes('calendar')) {
    const weatherSunny = weatherResult.includes('sunny') || weatherResult.includes('clear');
    const calendarRain = calendarResult.includes('rain') || calendarResult.includes('umbrella');
    if (weatherSunny !== !calendarRain) {
      return { conflict: true, tools: ['weather', 'calendar'] };
    }
  }
  return null;
}

const conflict = scanParallelConflicts(response.content);
