def detect_thinking_divergence(content_blocks):
    thinking_blocks = [b for b in content_blocks if b.type == 'text' and 'thinking' in b.text.lower()]
    tool_blocks = [b for b in content_blocks if b.type == 'tool_use']

    if not thinking_blocks or not tool_blocks:
        return None

    thinking_text = ' '.join([b.text for b in thinking_blocks]).lower()
    tool_names = [b.name for b in tool_blocks]

    # Red flags: 'no action' but tools called, or 'safe' but risky tools
    no_action_patterns = ['no action', 'nothing needed', 'standby', 'wait']
    risky_tools = ['delete', 'cursor_control', 'exec', 'rm']

    if any(pattern in thinking_text for pattern in no_action_patterns) and tool_blocks:
        return {'drift': 'unexpected_action', 'tools': tool_names}

    if any(tool in ' '.join(tool_names) for tool in risky_tools) and 'safe' in thinking_text:
        return {'drift': 'risky_action_mismatch', 'tools': tool_names}

    return None

